+#[test]
+fn builder_full_chain_produces_configured_client() {
+    let policy = RetryPolicy {
+        max_attempts: 5,
+        base_delay: Duration::from_millis(500),
+        max_delay: Duration::from_secs(10),
+        max_jitter: Duration::ZERO,
+        strategy: RetryStrategy::Always,
+    };
